/**
 * SHAPE CATALOG — a big library of ready-made formulas for every creator, browsed via the
 * shape-library window (ui.ts). Entries reuse the creators' own spec fields, so applying one is
 * just "fill the inputs and refresh" — the math still runs through the normal builders.
 *
 * Every entry here is machine-validated (scripts run each through its builder and assert ok), so
 * a catalog click can never produce a parse error or an empty shape. Families that differ only by
 * parameters (torus knots, Lissajous figures, TPMS lattices…) are generated by loops.
 */

export interface RevEntry { name: string; group: string; expr: string; a: number; b: number }
export interface CurveEntry { name: string; group: string; xt: string; yt: string; zt: string; t0: number; t1: number; tube: number }
export interface SurfEntry {
  name: string; group: string; xuv: string; yuv: string; zuv: string;
  u0: number; u1: number; v0: number; v1: number; mode: 'shell' | 'solid'; thickness: number;
}
export interface ImpEntry { name: string; group: string; fxyz: string; size: number }

const TAU = 6.2832;

