// ============================================================ parametric surfaces (~50)
// superellipsoid helper: sign(w)·|w|^p keeps fractional powers real
const sc = (w: string, p: number) => `sign(cos(${w}))*abs(cos(${w}))^${p}`;
const ss = (w: string, p: number) => `sign(sin(${w}))*abs(sin(${w}))^${p}`;
// note: keep p1 ≥ 0.5 — sharper vertical exponents make the poles collapse too slowly for the
// closure detector (the "pole" becomes a tiny ring at the domain's rounded ±π/2 ends)
const superEll = (name: string, p1: number, p2: number, rx: number, ry: number): SurfEntry => ({
  name, group: 'Superellipsoids',
  xuv: `${rx}*${sc('v', p1)}*${sc('u', p2)}`, yuv: `${ry}*${ss('v', p1)}`, zuv: `${rx}*${sc('v', p1)}*${ss('u', p2)}`,
  u0: -3.141593, u1: 3.141593, v0: -1.570796, v1: 1.570796, mode: 'solid', thickness: 0.1,
});

