// TPMS lattices are infinite — trim each to a ball of radius 2
const tpms = (name: string, f: string): ImpEntry => ({
  name, group: 'Lattices (TPMS)', fxyz: `max(${f}, x^2+y^2+z^2-4)`, size: 2.2,
});

